1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
13	
14	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	const COMPONENT_BASE_PRICE = 25;
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PRICE = 60;
25	
26	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const KNOWN_ITEM_TYPES = new Set([
35	  "sword",
36	  "amulet",
37	  "staff",
38	  "potion",
39	  "rune",
40	  "moonstone",
41	]);
42	
43	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
44	type Customer = { yearsWithMHPCO: number };
45	
46	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
47	
48	const mainItemBasePrice = (item: Item): number =>
49	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
50	
51	const componentGroupBasePrice = (count: number): number =>
52	  count === COMPONENT_BLOCK_SIZE
53	    ? COMPONENT_BLOCK_PRICE
54	    : count * COMPONENT_BASE_PRICE;
55	
56	const groupComponentsByType = (items: Item[]): Map<string, number> => {
57	  const groups = new Map<string, number>();
58	  for (const item of items) {
59	    if (!isComponent(item)) continue;
60	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
61	  }
62	  return groups;
63	};
64	
65	const sum = (numbers: number[]): number =>
66	  numbers.reduce((total, n) => total + n, 0);
67	
68	const policyBasePremium = (items: Item[]): number => {
69	  const mainItemPremiums = items
70	    .filter((item) => !isComponent(item))
71	    .map(mainItemBasePrice);
72	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
73	    componentGroupBasePrice,
74	  );
75	  return sum([...mainItemPremiums, ...componentGroupPremiums]);
76	};
77	
78	const curseSurcharge = (item: Item): number =>
79	  item.cursed ? mainItemBasePrice(item) * CURSE_SURCHARGE_RATE : 0;
80	
81	const highEnchantmentSurcharge = (item: Item): number =>
82	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
83	    ? mainItemBasePrice(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
84	    : 0;
85	
86	const itemSurcharges = (items: Item[]): number =>
87	  sum(items.map((item) => curseSurcharge(item) + highEnchantmentSurcharge(item)));
88	
89	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
90	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
91	    ? basePremium * LOYALTY_DISCOUNT_RATE
92	    : 0;
93	
94	type QuoteContext = { contractIndex?: number };
95	
96	const followUpDiscount = (
97	  context: QuoteContext,
98	  basePremium: number,
99	): number =>
100	  (context.contractIndex ?? 0) >= 1
101	    ? basePremium * FOLLOWUP_CONTRACT_DISCOUNT_RATE
102	    : 0;
103	
104	export const quote = (
105	  customer: Customer,
106	  items: Item[],
107	  context: QuoteContext = {},
108	): number => {
109	  for (const item of items) {
110	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
111	      throw new Error(`Unknown item type: ${item.type}`);
112	    }
113	  }
114	  const basePremium = policyBasePremium(items);
115	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
116	  return Math.ceil(
117	    basePremium +
118	      firstInsuranceSurcharge -
119	      loyaltyDiscount(customer, basePremium) -
120	      followUpDiscount(context, basePremium) +
121	      itemSurcharges(items) +
122	      PROCESSING_FEE,
123	  );
124	};
125	
126	type Policy = { items: Item[] };
127	type Damage = { itemType: string; amount: number };
128	type Incident = { cause?: string; damages: Damage[] };
129	type ClaimResult = { payout: number; remainingCap: number };
130	
131	const policyInsuranceSum = (policy: Policy): number =>
132	  sum(policy.items.map((item) => INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0));
133	
134	const policyCap = (policy: Policy): number =>
135	  policyInsuranceSum(policy) * CAP_MULTIPLIER;
136	
137	const findPolicyItem = (policy: Policy, itemType: string): Item | undefined =>
138	  policy.items.find((item) => item.type === itemType);
139	
140	const payoutRateForItem = (item: Item | undefined): number =>
141	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
142	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
143	    : 1;
144	
145	const payoutForDamage = (policy: Policy, damage: Damage): number => {
146	  const rate = payoutRateForItem(findPolicyItem(policy, damage.itemType));
147	  return Math.max(0, damage.amount * rate - DEDUCTIBLE);
148	};
149	
150	type QuoteStep = { op: "quote"; items: Item[] };
151	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
152	type ScenarioStep = QuoteStep | ClaimStep;
153	type Scenario = { customer: Customer; steps: ScenarioStep[] };
154	type QuoteResult = { premium: number };
155	type ScenarioStepResult = QuoteResult | ClaimResult;
156	type ScenarioOutcome = { results: ScenarioStepResult[] };
157	
158	const runQuoteStep = (customer: Customer, step: QuoteStep): QuoteResult => ({
159	  premium: quote(customer, step.items),
160	});
161	
162	const policyFromStep = (steps: ScenarioStep[], policyIndex: number): Policy => {
163	  const declaringStep = steps[policyIndex] as QuoteStep;
164	  return { items: declaringStep.items };
165	};
166	
167	const runClaimStep = (
168	  steps: ScenarioStep[],
169	  step: ClaimStep,
170	  paidByPolicy: Map<number, number>,
171	): ClaimResult => {
172	  const policy = policyFromStep(steps, step.policy);
173	  const alreadyPaid = paidByPolicy.get(step.policy) ?? 0;
174	  const result = claim(policy, step.incident, alreadyPaid);
175	  paidByPolicy.set(step.policy, alreadyPaid + result.payout);
176	  return result;
177	};
178	
179	export const runScenario = (scenario: Scenario): ScenarioOutcome => {
180	  const paidByPolicy = new Map<number, number>();
181	  const results: ScenarioStepResult[] = scenario.steps.map((step) =>
182	    step.op === "quote"
183	      ? runQuoteStep(scenario.customer, step)
184	      : runClaimStep(scenario.steps, step, paidByPolicy),
185	  );
186	  return { results };
187	};
188	
189	export const claim = (
190	  policy: Policy,
191	  incident: Incident,
192	  alreadyPaid: number = 0,
193	): ClaimResult => {
194	  const cap = policyCap(policy);
195	  const remainingBefore = cap - alreadyPaid;
196	  const desiredPayout = sum(
197	    incident.damages.map((damage) => payoutForDamage(policy, damage)),
198	  );
199	  const payout = Math.min(desiredPayout, remainingBefore);
200	  const remainingCap = remainingBefore - payout;
201	  return { payout: Math.floor(payout), remainingCap };
202	};
